
export function adjustSize(g: Element) {
  const guides = document.querySelectorAll(".guide");

  const gRect = JSON.parse(g.getAttribute("data-rect")!);
  const size = parseFloat(g.getAttribute("data-size")!);

  // Start with maximum bounds
  let left   = gRect.left   - size;
  let top    = gRect.top    - size;
  let right  = gRect.left   + gRect.width  + size;  // right edge
  let bottom = gRect.top    + gRect.height + size;  // note: only +size once on bottom

  // Shrink bounds to avoid overlapping other guides
  for (const other of guides) {
    if (other === g) continue;

    const oRect = JSON.parse(other.getAttribute("data-rect")!);

    const oLeft   = oRect.left;
    const oTop    = oRect.top;
    const oRight  = oRect.left + oRect.width;
    const oBottom = oRect.top  + oRect.height;

    // Check if other element overlaps the expanded bounds at all
    const overlapsH = oLeft < right  && oRight  > left;
    const overlapsV = oTop  < bottom && oBottom > top;

    if (!overlapsH || !overlapsV) continue;

    // It overlaps — shrink only the side(s) that are encroaching
    // Left side: other element is to the left and encroaching our left expansion
    if (oRight > left && oRight <= gRect.right) {
      left = gRect.left;
    }
    // Right side: other element is to the right and encroaching our right expansion
    if (oLeft < right && oLeft >= gRect.left) {
      right = gRect.right;
    }
    // Top side: other element is above and encroaching our top expansion
    if (oBottom > top && oBottom <= gRect.bottom) {
      top = gRect.top;
    }
    // Bottom side: other element is below and encroaching our bottom expansion
    if (oTop < bottom && oTop >= gRect.top) {
      bottom = gRect.bottom;
    }
  }

  // Convert back to left/top/width/height
  const finalLeft   = left;
  const finalTop    = top;
  const finalWidth  = right  - left;
  const finalHeight = bottom - top;

  // Apply as style
  (g as HTMLElement).style.left   = `${finalLeft}px`;
  (g as HTMLElement).style.top    = `${finalTop}px`;
  (g as HTMLElement).style.width  = `${finalWidth}px`;
  (g as HTMLElement).style.height = `${finalHeight}px`;
}